def main(follows_sent: int, follow_backs: int, dms_sent: int, replies_received: int, conversions: int, accounts_healthy: int, accounts_total: int) -> dict:
    # Calculate rates
    follow_back_rate = (follow_backs / max(follows_sent, 1)) * 100
    dm_response_rate = (replies_received / max(dms_sent, 1)) * 100
    conversion_rate = (conversions / max(replies_received, 1)) * 100
    account_health_rate = (accounts_healthy / max(accounts_total, 1)) * 100

    # Determine status
    if follow_back_rate >= 5 and dm_response_rate >= 15 and conversion_rate >= 50:
        overall_status = 'excellent'
    elif follow_back_rate >= 3 and dm_response_rate >= 10 and conversion_rate >= 30:
        overall_status = 'good'
    elif follow_back_rate >= 1 and dm_response_rate >= 5:
        overall_status = 'average'
    else:
        overall_status = 'needs_improvement'

    return {
        'follow_back_rate': round(follow_back_rate, 1),
        'dm_response_rate': round(dm_response_rate, 1),
        'conversion_rate': round(conversion_rate, 1),
        'account_health_rate': round(account_health_rate, 1),
        'overall_status': overall_status
    }

